/* === 队列消息定义 === */
typedef struct {
    uint32_t cmd;          /* 命令类型 */
    uint16_t param;        /* 参数 */
    uint8_t  data[32];     /* 负载数据 */
} sensor_msg_t;

/* === 队列实例 —— 深度 8，每条 sizeof(sensor_msg_t) === */
static QueueHandle_t sensor_queue;

void comms_init(void) {
    sensor_queue = xQueueCreate(8, sizeof(sensor_msg_t));
    configASSERT(sensor_queue);  /* 创建失败说明 RAM 不足 */
}

/* 生产者任务：采集传感器数据并发送到队列 */
void sensor_task(void *pv) {
    sensor_msg_t msg = {0};
    while (1) {
        msg.cmd = READ_ADC;
        msg.param = ADC_CHANNEL_3;
        msg.data[0] = HAL_ADC_GetValue(&hadc1);
        /* xQueueSend 超时 10 tick —— 队列满时不阻塞，丢弃最新数据 */
        if (xQueueSend(sensor_queue, &msg, pdMS_TO_TICKS(10)) != pdPASS) {
            /* 队列满时递增丢包计数器 */
            stats_drop_count++;
        }
        vTaskDelay(pdMS_TO_TICKS(50));  /* 20Hz 采样率 */
    }
}

/* 消费者任务：从队列获取并处理 */
void control_task(void *pv) {
    sensor_msg_t msg;
    while (1) {
        /* xQueueReceive 阻塞等待 —— 队列为空时释放 CPU */
        if (xQueueReceive(sensor_queue, &msg, portMAX_DELAY) == pdPASS) {
            if (msg.cmd == READ_ADC) {
                pid_update(msg.data[0]);  /* 更新 PID 控制器 */
            }
        }
    }
}

/* === 互斥锁 —— 用于保护共享资源 === */
static SemaphoreHandle_t xSharedMutex;

/* === 中断安全的数据通道 === */
static QueueHandle_t xISRToTaskQ;

void SystemInit(void) {
    xSharedMutex = xSemaphoreCreateMutex();
    xISRToTaskQ = xQueueCreate(4, sizeof(uint32_t));
}

/* === 中断服务程序 (SPI Rx DMA 完成中断) === */
void DMA2_Stream3_IRQHandler(void) {
    HAL_DMA_IRQHandler(&hdma_spi2_rx);
    /* DMA 传输完成后，在中断中将接收到的字节发送到队列 */
    uint32_t byte = SPI2->DR;  /* 读取 SPI 数据寄存器 */
    BaseType_t xHigherPriorityTaskWoken = pdFALSE;
    /* xQueueSendFromISR 是中断安全的 —— 注意 xHigherPriorityTaskWoken 参数 */
    xQueueSendFromISR(xISRToTaskQ, &byte, &xHigherPriorityTaskWoken);
    /* 如果 xHigherPriorityTaskWoken 为 pdTRUE，需要在退出中断前触发上下文切换 */
    portYIELD_FROM_ISR(xHigherPriorityTaskWoken);
}

/* === 任务 A：持有互斥锁，耗时操作 === */
void low_priority_task(void *pv) {
    while (1) {
        if (xSemaphoreTake(xSharedMutex, pdMS_TO_TICKS(100)) == pdPASS) {
            /* 持有锁期间执行耗时操作 —— 高优先级任务会被阻塞 */
            HAL_ADC_Start(&hadc1);
            HAL_ADC_PollForConversion(&hadc1, pdMS_TO_TICKS(10));
            uint32_t adc_val = HAL_ADC_GetValue(&hadc1);
            /* 释放锁 —— 如果有高优先级任务在等待，优先级继承会自动撤销 */
            xSemaphoreGive(xSharedMutex);
        }
        vTaskDelay(pdMS_TO_TICKS(500));
    }
}

/* === 陷阱演示：错误的非阻塞接收循环 === */
/* ❌ 错误示范 —— 忙等待，100% CPU */
void bad_consumer_task(void *pv) {
    msg_t msg;
    while (1) {
        if (xQueueReceive(xQueue, &msg, 0) == pdPASS) {
            process(&msg);
        }
        /* 没有 vTaskDelay！这个循环以 MHz 级别运行 */
    }
}

/* ✅ 正确做法 1：阻塞接收，队列为空时让出 CPU */
void good_consumer_blocking(void *pv) {
    msg_t msg;
    while (1) {
        if (xQueueReceive(xQueue, &msg, portMAX_DELAY) == pdPASS) {
            process(&msg);
        }
    }
}

/* ✅ 正确做法 2：非阻塞 + 让步 */
void good_consumer_nonblock(void *pv) {
    msg_t msg;
    while (1) {
        if (xQueueReceive(xQueue, &msg, 0) == pdPASS) {
            process(&msg);
        } else {
            vTaskDelay(pdMS_TO_TICKS(1));  /* 让出 1ms */
        }
    }
}

/* === 重构前：共享全局变量（坏味道：数据泥团 + 广义赋值）=== */
typedef struct {
    int16_t target_speed;
    int16_t current_rpm;
    uint8_t  state;       /* 0=stop, 1=running, 2=error */
} motor_state_t;

static motor_state_t motor_state;  /* 全局可变状态 */

void sensor_task(void *pv) {
    while (1) {
        motor_state.current_rpm = HAL_TIM_ReadCounter(&htim4);  /* 读编码器 */
        motor_state.state = (motor_state.current_rpm > 100) ? 1 : 0;
        vTaskDelay(pdMS_TO_TICKS(10));
    }
}

void control_task(void *pv) {
    while (1) {
        int16_t error = motor_state.target_speed - motor_state.current_rpm;
        int16_t pwm = pid_compute(error);  /* PID 计算 */
        __HAL_TIM_SET_COMPARE(&htim3, TIM_CHANNEL_1, pwm);
        vTaskDelay(pdMS_TO_TICKS(10));  /* 隐式依赖 sensor_task 的 10ms 周期 */
    }
}

/* === 重构后：基于消息队列的显式通信 === */
typedef enum { MSG_UPDATE_RPM, MSG_SET_SPEED } msg_type_t;
typedef struct {
    msg_type_t type;
    int16_t    value;  /* RPM 或目标速度 */
} motor_msg_t;

static QueueHandle_t xSensorQueue;
static QueueHandle_t xCommandQueue;

void comms_init(void) {
    xSensorQueue  = xQueueCreate(4, sizeof(motor_msg_t));
    xCommandQueue = xQueueCreate(4, sizeof(motor_msg_t));
}

void sensor_task(void *pv) {
    motor_msg_t msg = { .type = MSG_UPDATE_RPM };
    while (1) {
        msg.value = HAL_TIM_ReadCounter(&htim4);
        xQueueSend(xSensorQueue, &msg, pdMS_TO_TICKS(10));
        vTaskDelay(pdMS_TO_TICKS(10));
    }
}

void control_task(void *pv) {
    motor_msg_t msg;
    int16_t target = 0;
    while (1) {
        xQueueReceive(xSensorQueue, &msg, portMAX_DELAY);
        if (msg.type == MSG_UPDATE_RPM) {
            int16_t error = target - msg.value;
            int16_t pwm = pid_compute(error);
            __HAL_TIM_SET_COMPARE(&htim3, TIM_CHANNEL_1, pwm);
        }
        /* 接收来自上层的速度设定命令 */
        if (xQueueReceive(xCommandQueue, &msg, pdMS_TO_TICKS(100)) == pdPASS) {
            if (msg.type == MSG_SET_SPEED) target = msg.value;
        }
    }
}
